var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"헉…?!","JPN":"はっ……！？","ENG":"*Gasp*","TWN":"嚇……？"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"집이구나… 다행이다.","JPN":"家か……よかった。","ENG":"I'm home... Whew.","TWN":"我在家嗎……太好了。"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"매일 악몽 꾸는 것 같은데, 괜찮은 거야?","JPN":"毎日悪夢にうなされてるみたいだけど、大丈夫？","ENG":"You look like you have a nightmare every night. Are you okay?","TWN":"你好像每天都在做惡夢，沒事吧？"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"응… 어쩔 수 없지 뭐.","JPN":"ん……まあ、仕方ないよ。","ENG":"Yeah... But there's nothing I can do about it.","TWN":"是啊……但我也沒什麼好辦法。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"그나저나 오늘은 고물상 일을 하는 날인데, 괜찮으면 같이 나가지 않을래?","JPN":"ところで今日は古物商の仕事をする日なんだけど、よかったら一緒に行かない？","ENG":"Anyway, today's the day I work at the junk shop. Care to tag along if it's okay with you?","TWN":"話說今天要幫破銅爛鐵店工作，瑪卡要一起來嗎？"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"보리스 아저씨한테 총기류를 고쳐주려고?","JPN":"ボリスおじさんの武器を直しに行くの？","ENG":"Are you going there to help Boris fix firearms?","TWN":"是幫布里斯大叔修理槍械嗎？"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"응. 총기류도 있긴 하지만 보통 의수를 많이 맡아주곤 해.","JPN":"銃とかの武器もあるけど、普段は義肢を頼まれることが多いかな。","ENG":"Yeah. Some are firearms, but it's normally a lot of prosthetics.","TWN":"嗯。雖然也有槍械，但通常是修理義肢比較多。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"시린그라드에는 팔이나 다리를 의수로 대체하는 사람들이 많거든.","JPN":"シリングラードには腕や足を義肢にしている人が多いの。","ENG":"There are a lot of people in Ciringrad who have their limbs replaced with prosthetics.","TWN":"在錫林格勒，有很多人用義肢呢。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"내가 도와주지 않으면 많이 불편할 것 같아서 늘 도와드리고 있어.","JPN":"やっぱり不便そうだから、私がいつも手伝っているんだ。","ENG":"I help out because, without me, it'll be inconvenient for them.","TWN":"不好好修的話，大家會很不方便，所以我一直在幫忙。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"알았어. 그럼 내가 수레 끌어줄게.","JPN":"わかった。じゃあ私が荷車を引く。","ENG":"Okay. Then I'll pull the cart instead.","TWN":"明白了，那我來拉車吧。"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"헤헤. 말 안 해도 찰떡같이 알아듣는구나!","JPN":"えへっ、察しがよくて何より！","ENG":"Hehe. You already know what to do without even me telling you!","TWN":"嘿嘿，不用說你就懂我的意思啦！"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"오늘은 마을 곳곳을 돌아다녀 볼 거니까, 분명 마브카한테도 좋은 시간이 될 거야!","JPN":"今日は村のあちこちを回るから、マブカにも有意義な時間になるよ！","ENG":"Today, we're going to go around the village, so I'm sure it'll be a good time for you too, Mavka!","TWN":"今天要在村子裡到處跑，瑪卡肯定也會喜歡的！"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"아주머니! 저 왔어요!","JPN":"おばさん！　サシャです！","ENG":"Ma'am! I'm here!","TWN":"我來了！阿姨！"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"BREAD_DOLL_NPC_NULL","text":{"KOREA":"사샤구나. 마브카도 함께네?","JPN":"サシャ、いらっしゃい。マブカも一緒なのね。","ENG":"It's you, Sasha. And Mavka's with you too.","TWN":"是莎夏啊，瑪卡也一起來了嗎？"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":{"char_id":"BREAD_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BREAD_DOLL_NPC_NULL","text":{"KOREA":"둘이서 수레를 끌고 다니는 모습이 정말 귀엽구나.","JPN":"二人で荷車を引いて回ってるの、とても可愛いね。","ENG":"You two look so cute pulling that cart around.","TWN":"你們兩個拉著車的樣子真可愛。"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":{"char_id":"BREAD_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"에헤헤. 정말요?","JPN":"えへへ、本当ですか？","ENG":"Ehehe. Really?","TWN":"嘿嘿，真的嗎？"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"예전에 수리 요청하신 물건 고쳐왔어요.","JPN":"この前修理を頼まれたやつ、持って来ました。","ENG":"I'm here to fix an item you requested for repair.","TWN":"之前修理的東西已經修好了。"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"BREAD_DOLL_NPC_NULL","text":{"KOREA":"매번 신경 써줘서 고맙구나. 자, 보수는 여깄단다.","JPN":"いつもありがとう。さ、報酬はこちらよ。","ENG":"I appreciate you doing this every time. Here's your pay.","TWN":"每次都麻煩你了，謝謝。來，這是報酬。"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":{"char_id":"BREAD_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"헤헤. 감사합니다 아주머니!","JPN":"えへへ、ありがとうございます！","ENG":"Hehe. Thank you so much, ma'am!","TWN":"嘿嘿。謝謝阿姨！"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"<color=#ffd34c>물건만 두고 가시오.</color> 라고 적혀있네.","JPN":"<color=#ffd34c>モノだけおいて行きなさい</color>、って書かれてる。","ENG":"It says, <color=#ffd34c>\\"Leave the stuff here and go.\\"</color>","TWN":"上面寫著<color=#ffd34c>把東西放下就走</color>呢。"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"가끔은 얼굴 좀 보여주시지.","JPN":"たまには顔見せてくれてもいいのに。","ENG":"I wish he'd show his face one day.","TWN":"偶爾也露露臉吧。"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"싸우기라도 했어?","JPN":"喧嘩でもしたの？","ENG":"Did you two fight or something?","TWN":"和人吵架了嗎？"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"아니. 여기 사시는 분은 아마 추방당한 분이었을 거야.","JPN":"ううん、ここの方はたぶん、追放されたんだと思う。","ENG":"No. He's just someone who was exiled from the country.","TWN":"不是，住在這裡的人應該是被驅逐的。"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"마음의 상처가 깊으신가 봐. 나도 거의 본 적 없거든.","JPN":"心の傷が深いんだろうね。私もほとんど顔を見たことがないの。","ENG":"I think he's pretty scarred from it. I've never seen him either.","TWN":"可能心裡的傷口很深，我也幾乎沒見過他。"},"stage":{"bg":"CIRIN_VILLAGE_02","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};